<?php
 declare(strict_types=1); namespace tapmeppe\composer\blueprint; class Resources { static function copy(string $source, string $target): bool { if (!is_dir($source)) return copy($source, $target); self::createDirectory($target); foreach (scandir($source) as $resource) { if ( $resource == '.' || $resource == '..' || self::copy("$source/$resource", "$target/$resource") ) continue; return false; } return true; } static function createDirectory(string $directory): string { if (!is_dir($directory)) mkdir($directory, 0755, true); return $directory; } static function delete(...$resources): bool { return array_reduce( array_map( function (string $resource) { $i = 0; do { if (self::remove($resource)) return true; } while (++$i < 3); return false; }, $resources ), fn($result, $step) => $result && $step, true ); } static function download(string $source, string $target, int $timeout = 60): ?string { $sourceStream = curl_init($source); $targetStream = fopen($target, 'wb'); curl_setopt_array($sourceStream, [ CURLOPT_FILE => $targetStream, CURLOPT_FOLLOWLOCATION => true, CURLOPT_FAILONERROR => true, CURLOPT_TIMEOUT => $timeout, ]); if (!curl_exec($sourceStream)) { fclose($targetStream); throw new \Exception('Download failed: ' . curl_error($sourceStream)); } fclose($targetStream); return $target; } static function empty(string $directory): bool { return array_reduce( array_map(self::delete(...), glob("$directory/*")), fn($result, $step) => $result && $step, true ); } static function exists(string $resource): bool { return file_exists($resource); } static function extractTar(string $source, string $target): bool { return new \PharData($source)->extractTo($target, null, true); } static function extractZip(string $source, string $target): bool { $zip = new \ZipArchive(); return $zip->open($source) && $zip->extractTo($target) && $zip->close(); } static function fetch(string $url, array $options, callable $success, callable $failure) { try { $curl = curl_init($url); curl_setopt_array( $curl, [ CURLOPT_RETURNTRANSFER => true, CURLOPT_CONNECTTIMEOUT => 5, CURLOPT_TIMEOUT => 10, ] + $options ); $response = curl_exec($curl); if ($number = curl_errno($curl)) throw new \Exception(sprintf("Fetching '%s' failed.\n Error number %d\n%s", $url, $number, curl_error($curl))); else $success($response); } catch (\Throwable $throwable) { $failure($throwable->getMessage()); } } static function fetchJSON(string $url, array $fallback = [], array $options = []): mixed { $object = []; self::fetch( $url, [ CURLOPT_HTTPHEADER => [ 'Content-Type: application/json', ], ] + $options, function ($response) use (&$object, $fallback) { $object = Utilities::merge($fallback, json_decode($response, true) ?: []); }, function ($error) use (&$object, $fallback) { $object = $fallback; }, ); return $object; } static function getPathOptimised(string $path): string { return str_replace(DIRECTORY_SEPARATOR, '/', $path); } static function getPathRelative(string $path, string $base): string { return trim(str_replace($base, '', $path), '/'); } static function getPathTemporary(string $name, bool $framework = true): string { return $framework ? Resources::createDirectory(TAPMEPPE_RESOURCES . '/temporary') . "/$name" : self::getPathOptimised( TAPMEPPE_MODE_DEVELOPMENT ? sys_get_temp_dir() . "/$name" : tempnam(sys_get_temp_dir(), $name) ); } static function glob(string $pattern, int $flag = 0, string ...$exclusions): array { return array_diff(glob($pattern, $flag), $exclusions); } static function list(string $directory, string ...$exclusions): array { try { return array_diff(@scandir($directory), ['.', '..', ...$exclusions]); } catch (\Throwable $th) { return []; } } static function listRecursive(string $directory, callable $callback, string ...$exclusions): void { foreach (self::list($directory, ...$exclusions) as $name) { is_dir($resource = "$directory/$name") ? self::listRecursive($resource, $callback, ...$exclusions) : $callback($name, $resource); } } static function read(string $file, string $fallback = ''): string { try { if ($content = @file_get_contents($file)) return $content; } catch (\Throwable $throwable) { } return $fallback; } static function readJSON(string $file, array $fallback = []): array { try { if ($object = json_decode(self::read($file, '{}'), true)) return Utilities::merge($fallback, (array) $object); else throw new \Exception(sprintf("Failed to decode JSON file '%s'.\nError: %s.", $file, json_last_error_msg())); } catch (\Throwable $throwable) { } return $fallback; } static function readJSONcomposer(array $fallback = ['name' => TAPMEPPE_UMBRELLA, 'version' => TAPMEPPE_VERSION]): object { return (object) self::readJSON(TAPMEPPE_FRAMEWORK . '/composer.json', $fallback); } static function readReplace(string $file, array $needles, array $raw = []): string { return Utilities::replace(self::read($file), $needles, $raw); } static function replace(string $file, array $patterns): bool { $extension = pathinfo($file, PATHINFO_EXTENSION); switch ($extension) { case 'env': $content = preg_replace_callback( sprintf("/(%s)[ \t]*=[^\n]*/", implode('|', array_keys($patterns))), function ($matches) use (&$patterns): string { $value = strval($patterns[$matches[1]]); unset($patterns[$matches[1]]); if (str_contains($value, ' ')) { if (!str_starts_with($value, '"')) $value = "\"$value"; if (!str_ends_with($value, '"')) $value .= '"'; } return sprintf('%s=%s', $matches[1], $value); }, self::read($file) ); foreach ($patterns as $key => $value) { $value = strval($value); if (str_contains($value, ' ')) { if (!str_starts_with($value, '"')) $value = "\"$value"; if (!str_ends_with($value, '"')) $value .= '"'; } $content .= "\n$key=$value"; } return self::write($file, trim($content) . "\n"); default: return false; } } static function write(string $file, string $content, int $flags = 0): bool { return file_put_contents($file, $content, $flags) !== false; } static function writeJSON(string $file, mixed $content, int $flags = JSON_PRETTY_PRINT): bool { return self::write( $file, preg_replace('/ {4}/', "\t", (string) json_encode($content, $flags)) ); } private static function remove(string $resource): bool { if (is_dir($resource)) { $resources = self::list($resource); foreach ($resources as $resource1) { is_dir("$resource/$resource1") ? self::remove("$resource/$resource1") : unlink("$resource/$resource1"); } return rmdir($resource); } else return !is_file($resource) || unlink($resource); } } 